// HashPatternNode represents a hash pattern in pattern matching.
//
//     foo => { a: 1, b: 2 }
//            ^^^^^^^^^^^^^^
//
//     foo => { a: 1, b: 2, **c }
//            ^^^^^^^^^^^^^^^^^^^
//
//     foo => Bar[a: 1, b: 2]
//            ^^^^^^^^^^^^^^^
//
//     foo in { a: 1, b: 2 }
//            ^^^^^^^^^^^^^^
pub struct HashPatternNode {
pub:
	// Base node metadata shared by all Prism AST nodes.
	base NodeBase

	// Represents the optional constant preceding the Hash.
	//
	//     foo => Bar[a: 1, b: 2]
	//          ^^^
	//
	//     foo => Bar::Baz[a: 1, b: 2]
	//          ^^^^^^^^
	constant ?Node

	// Represents the explicit named hash keys and values.
	//
	//     foo => { a: 1, b:, ** }
	//              ^^^^^^^^
	elements []Node

	// Represents the rest of the Hash keys and values. This can be named, unnamed, or explicitly forbidden via `**nil`, this last one results in a `NoKeywordsParameterNode`.
	//
	//     foo => { a: 1, b:, **c }
	//                        ^^^
	//
	//     foo => { a: 1, b:, ** }
	//                        ^^
	//
	//     foo => { a: 1, b:, **nil }
	//                        ^^^^^
	rest ?Node

	// The location of the opening brace.
	//
	//     foo => { a: 1 }
	//            ^
	//
	//     foo => Bar[a: 1]
	//               ^
	opening_loc ?Location

	// The location of the closing brace.
	//
	//     foo => { a: 1 }
	//                   ^
	//
	//     foo => Bar[a: 1]
	//                    ^
	closing_loc ?Location
}

