	// The `if_keyword_loc` field will be `nil` when the `IfNode` represents a ternary expression.
	if_keyword_loc ?Location

	// The node for the condition the `IfNode` is testing.
	//
	//     if foo
	//        ^^^
	//       bar
	//     end
	//
	//     bar if foo
	//            ^^^
	//
	//     foo ? bar : baz
	//     ^^^
