	//              ^^^
	expression Node

	// The location of the `^` operator
	//
	//     foo in ^(bar)
	//            ^
	operator_loc Location

	// The location of the opening parenthesis.
	//
	//     foo in ^(bar)
	//             ^
	lparen_loc Location

	// The location of the closing parenthesis.
	//
	//     foo in ^(bar)
	//                 ^
	rparen_loc Location
}

