// UnlessNode represents the use of the `unless` keyword, either in the block form or the modifier form.
//
//     bar unless foo
//     ^^^^^^^^^^^^^^
//
//     unless foo then bar end
//     ^^^^^^^^^^^^^^^^^^^^^^^
pub struct UnlessNode {
pub:
	// Base node metadata shared by all Prism AST nodes.
	base NodeBase

	// The location of the `unless` keyword.
	//
	//     unless cond then bar end
	//     ^^^^^^
	//
	//     bar unless cond
	//         ^^^^^^
	keyword_loc Location

	// The condition to be evaluated for the unless expression. It can be any [non-void expression](https://github.com/ruby/prism/blob/main/docs/parsing_rules.md#non-void-expression).
	//
	//     unless cond then bar end
	//            ^^^^
	//
	//     bar unless cond
	//                ^^^^
	predicate Node

	// The location of the `then` keyword, if present.
	//
	//     unless cond then bar end
	//                 ^^^^
	then_keyword_loc ?Location

	// The body of statements that will executed if the unless condition is
	// falsey. Will be `nil` if no body is provided.
	//
	//     unless cond then bar end
	//                      ^^^
	statements ?Node

	// The else clause of the unless expression, if present.
	//
	//     unless cond then bar else baz end
	//                          ^^^^^^^^
	else_clause ?Node

	// The location of the `end` keyword, if present.
	//
	//     unless cond then bar end
	//                          ^^^
	end_keyword_loc ?Location
}

